import { Heading, Meta } from '@storybook/addon-docs/blocks';
import { colorPrimitives } from '../styles';

<Meta title="foundations/Colors" />

# Colors

Foundational colors to be used by different [themes](/docs/foundations-theme--docs).
These colors are not context-specific, and should not be used directly in components.

All variables are sourced from [Untitled UI](https://www.untitledui.com/components/color-styles).

<div>
  {Object.values(colorPrimitives).map((item) => (
    <div key={item.id} style={{ marginBlock: 40 }}>
      <Heading>{item.name}</Heading>
      <div class="docs-colorSwatch sb-unstyled">
        {Object.entries(item.values).map(([weight, hex]) => {
          const variable = `${item.id}-${weight}`;
          return (
            <div class="docs-colorItem" key={variable}>
              <div class="color" style={{ backgroundColor: hex }} />
              <div class="info">
                <div class="variable">{variable}</div>
                <div class="hex">{hex}</div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  ))}
</div>

<style>
  {`
    .docs-colorSwatch {
      color-scheme: light;
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
      row-gap: 12px;
    }

    .docs-colorItem {
      background-color: var(--bg-primary);
      font: var(--type-text-xs);
      overflow: hidden;
    }

    .docs-colorItem .color {
      height: 40px;
    }

    .docs-colorItem .info {
      padding-block: 4px;
      padding-inline: 8px;
    }

    .docs-colorItem .variable {
      color: var(--text-primary);
      font-weight: 500;
    }

    .docs-colorItem .hex {
      color: var(--text-tertiary);
      font-size: 11px;
      font-weight: 400;
    }
  `}
</style>

foundations-theme--docs.content:
import { Heading, Meta, Title } from '@storybook/addon-docs/blocks';
import { defaultTheme, colorNameLookup, colorDictionary } from '../styles';

<Meta title="foundations/Theme" />

# Theme

Color variables that are defined based on their intended use or meaning. They
provide context and convey information, such as status, state, or action.

All variables are sourced from [Untitled UI](https://www.untitledui.com/components/color-styles).

Themes support a light mode and dark mode. The color scheme will match your system settings by default, or can be manually applied by setting the `color-scheme` property.

- For **light-mode**, apply the `color-scheme: light` property
- For **dark-mode**, apply the `color-scheme: dark` property

<div>
  {Object.entries(defaultTheme.colors).map(([groupKey, group]) => (
    <div key={groupKey} style={{ marginBlock: 40 }}>
      <Heading>{colorDictionary[groupKey].name}</Heading>

      <div class="list sb-unstyled">
        {Object.entries(group.values).map(([weight, hex]) => {
          const variableName = `${group.id}-${weight}`
          const cssVariable=`var(--${variableName})`
          const lightSchemeValue = hex[0]
          const darkSchemeValue = hex[1]

          return (
            <div class="row">
              <div class="variableName">
                {variableName}
              </div>

              <div class="colorChip">
                <div class="color"
                  style={{ backgroundColor: cssVariable}} />
                <div>
                  <div class="variable">{colorNameLookup(lightSchemeValue)}</div>
                  <div class="hex">{lightSchemeValue}</div>
                </div>
              </div>

              <div class="colorChip colorChip-dark">
                <div class="color"
                  style={{ backgroundColor: cssVariable}} />
                <div>
                  <div class="variable">{colorNameLookup(darkSchemeValue)}</div>
                  <div class="hex">{darkSchemeValue}</div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>

))}

</div>

## Usage

```css
.someClass {
  --_border-color: var(--border-primary);
  border: 1px solid var(--_border-color);
}
.someClass.error {
  --_border-color: var(--border-error);
}
.someClass.warning {
  --_border-color: var(--border-warning);
}
.someClass.dark {
  /* apply the dark color scheme */
  color-scheme: dark;
}

/* you can also create global helper classes for dark/light modes */
.light-mode {
  color-scheme: light;
}
.dark-mode {
  color-scheme: dark;
}
```

<style>
  {`
    .list {
      color-scheme: light;
      display: grid;
      gap: 12px;
    }

    .row {
      align-items: center;
      display: grid;
      gap: 12px;
      grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    }

    .variableName {
      color: var(--text-primary);
      font: 500 var(--type-text-md);
    }

    .colorChip {
      align-items: center;
      background-color: var(--bg-primary);
      border: 1px solid var(--border-secondary);
      border-radius: 12px;
      color: var(--text-primary);
      display: flex;
      font: var(--type-text-xs);
      gap: 6px;
      padding-block: 4px;
      padding-inline: 4px 12px;
    }

    .colorChip-dark {
      color-scheme: dark;
    }

    .colorChip .color {
      aspect-ratio: 1 / 1;
      background-clip: content-box;
      border: 1px solid var(--border-secondary);
      border-radius: 8px;
      box-sizing: border-box;
      flex-shrink: 0;
      padding-block: 4px;
      padding-inline: 4px;
      width: 40px;
    }

    .colorChip .variable {
      color: var(--text-primary);
      font: 500 var(--type-text-sm);
    }

    .colorChip .hex {
      color: var(--text-tertiary);
      font: 400 var(--type-text-xs);
    }
  `}
</style>

