import { Heading, Meta, Subheading } from '@storybook/addon-docs/blocks';
import { typographyDictionary, defaultTheme } from '../styles';

<Meta title="foundations/Typography" />

# Typography

Font is [Inter](https://fonts.google.com/specimen/Inter) and variables sourced from [Untitled UI](https://www.untitledui.com/components/typography-styles).

<div>
  {Object.entries(defaultTheme.typography).map(([groupKey, group]) => (
    <div key={groupKey} style={{ marginBlock: 40 }}>
      <Heading>{typographyDictionary[groupKey].name}</Heading>

      <p>
        {typographyDictionary[groupKey].description}
      </p>
      <p>
        <code>font-family: {group.family}</code>
      </p>

      <div class="list sb-unstyled">
        {Object.entries(group.values).map(([variantKey, variant]) => {
          const variable = `type-${group.id}-${variantKey}`

          return (
            <div class="row" key={variable}>
              <div class="variableName">
                {variable}
              </div>

              <div>
                {`${variant.size} / ${variant.lineHeight}`}
              </div>

              <div style={{ font: `var(--${variable})` }}>
                {`Hello world`}
              </div>
            </div>
          )
        })}
      </div>
    </div>

))}

</div>

<style>
  {`
    .list {
      color-scheme: light;
      display: grid;
      gap: 12px;
    }

    .row {
      align-items: center;
      color: var(--text-primary);
      display: grid;
      gap: 12px;
      grid-template-columns: 1fr 1fr 2fr;
    }

    .variableName {
      font: 500 var(--type-text-md);
    }
  `}
</style>

## Usage

Use the CSS `font` property and combine the weight with the variable:

```css
/* bold and large */
font: 700 var(--type-display-lg);

/* regular and small */
font: 400 var(--type-text-sm);
```

